package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeUnknown                        = "unknown"
)

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"no viable provider"):
		return FailureModeNoViableProvider
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""
}

// containsAny reports whether s contains any of the given substrings. s is
// assumed to already be lower-cased by the caller.
func containsAny(s string, needles ...string) bool {
	for _, n := range needles {
		if n == "" {
			continue
		}
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

// classifyLandingFailureMode computes the final failure_mode for a result
// after the orchestrator has made its landing decision. It prefers
// landing-specific signals (merge conflict, gate failure) over the worker's
// classification and falls back to workerMode for worker-level failures
// (agent execution failed, context overflow, etc.). Returns "" when the
// bead merged cleanly.
func classifyLandingFailureMode(landingOutcome, landingReason string, gateResults []GateCheckResult, workerMode string) string {
	switch landingOutcome {
	case "merged":
		return ""
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	case "error":
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	case "preserved":
		switch landingReason {
		case "merge conflict", "merge failed", "ff-merge not possible":
			return FailureModeMergeConflict
		case "post-run checks failed":
			return classifyGateFailure(gateResults)
		case RatchetPreserveReason:
			return FailureModeRatchetMiss
		case OperatorCancelReason:
			return ""
		}
		// Other preserved reasons (e.g. "agent execution failed",
		// "--no-merge specified") defer to the worker's classification.
		if workerMode != "" {
			return workerMode
		}
		return FailureModeUnknown
	}
	if workerMode != "" {
		return workerMode
	}
	return FailureModeUnknown
}

// classifyGateFailure inspects failed gate results to distinguish
// build_failure from test_failure. Gate definitions that fail to compile
// before running (go build, tsc, cargo build) typically surface build
// diagnostics in stderr; test runners surface test failure markers. When
// ambiguous, defaults to test_failure since the post-run checks gate is
// test-oriented by convention.
func classifyGateFailure(gateResults []GateCheckResult) string {
	for _, gr := range gateResults {
		if gr.Status != "fail" {
			continue
		}
		combined := strings.ToLower(gr.Stdout + "\n" + gr.Stderr)
		if containsAny(combined,
			"build failed",
			"compilation failed",
			"compile error",

}

type WorkerLifecycleEvent struct {
	Action    string    `json:"action"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
	Detail    string    `json:"detail,omitempty"`
	BeadID    string    `json:"bead_id,omitempty"`
}

type WorkerRecord struct {
	ID    string `json:"id"`
	Kind  string `json:"kind"`
	State string `json:"state"`
	// Substate is a non-terminal annotation on a running worker. Currently
	// the only value is "idle" — set when the long-running drain loop has
	// no ready work and is sleeping between polls (ddx-dc157075 AC #5).
	// Cleared as soon as the loop picks up a candidate. Always empty for
	// terminal states (exited/failed/stopped/reaped).
	Substate       string                 `json:"substate,omitempty"`
	Status         string                 `json:"status,omitempty"`
	ProjectRoot    string                 `json:"project_root"`
	Harness        string                 `json:"harness,omitempty"`
	Provider       string                 `json:"provider,omitempty"`
	Model          string                 `json:"model,omitempty"`
	Profile        string                 `json:"profile,omitempty"`
	Effort         string                 `json:"effort,omitempty"`
	Once           bool                   `json:"once,omitempty"`
	PollInterval   string                 `json:"poll_interval,omitempty"`
	StartedAt      time.Time              `json:"started_at,omitempty"`
	FinishedAt     time.Time              `json:"finished_at,omitempty"`
	Error          string                 `json:"error,omitempty"`
	StdoutPath     string                 `json:"stdout_path,omitempty"`
	SpecPath       string                 `json:"spec_path,omitempty"`
	Attempts       int                    `json:"attempts,omitempty"`
	Successes      int                    `json:"successes,omitempty"`
	Failures       int                    `json:"failures,omitempty"`
	CurrentBead    string                 `json:"current_bead,omitempty"`
	LastError      string                 `json:"last_error,omitempty"`
	LastResult     *WorkerExecutionResult `json:"last_result,omitempty"`
	CurrentAttempt *CurrentAttemptInfo    `json:"current_attempt,omitempty"`
	RecentPhases   []PhaseTransition      `json:"recent_phases,omitempty"`
	LastAttempt    *LastAttemptInfo       `json:"last_attempt,omitempty"`
	Lifecycle      []WorkerLifecycleEvent `json:"lifecycle,omitempty"`
	LandSummary    *CoordinatorMetrics    `json:"land_summary,omitempty"`
	// PID is the OS process id of an external worker subprocess, if any.
	// Zero for purely in-process (goroutine-only) workers. Surfaced so the
	// autonomous watchdog can send SIGTERM/SIGKILL to the process group when
	// cancelling the context is not enough.
	PID int `json:"pid,omitempty"`
	// ReapReason is populated when the watchdog forcibly terminates a worker;
	// set to "watchdog" today.
	ReapReason string `json:"reap_reason,omitempty"`
	// PIDAlive is a computed field populated by List(); it is never persisted
	// to disk. True when PID > 0 and the process is alive, false when PID > 0
	// but the process has exited. Omitted (nil) when PID == 0 (goroutine-only).
	PIDAlive *bool `json:"pid_alive,omitempty"`
}

type WorkerExecutionResult struct {
	BeadID     string `json:"bead_id,omitempty"`
	AttemptID  string `json:"attempt_id,omitempty"`
	WorkerID   string `json:"worker_id,omitempty"`
	Harness    string `json:"harness,omitempty"`
	Tier       string `json:"tier,omitempty"`
	Provider   string `json:"provider,omitempty"`
	Model      string `json:"model,omitempty"`
	Status     string `json:"status,omitempty"`
	Detail     string `json:"detail,omitempty"`
	SessionID  string `json:"session_id,omitempty"`
	BaseRev    string `json:"base_rev,omitempty"`
	ResultRev  string `json:"result_rev,omitempty"`
	RetryAfter string `json:"retry_after,omitempty"`
}

type workerHandle struct {
	record  WorkerRecord
	cancel  context.CancelFunc
	logBuf  *bytes.Buffer
	logFile *os.File
	// progressCh receives ProgressEvents from the execute-bead loop.
	// The WorkerManager drains this channel to update WorkerRecord and
	// broadcast to SSE subscribers.
	progressCh chan agent.ProgressEvent
	// progressSubs holds active SSE subscriber channels for this worker.
	progressSubs []chan agent.ProgressEvent
	// progressDone is closed when drainProgress exits, signalling that
	// no further events will arrive and all new subscriptions should
	// receive an immediately-closed channel.
	progressDone chan struct{}
	// lastPhaseTS is the wall-clock time of the most recent non-heartbeat
	// ProgressEvent. The watchdog uses this to detect stalled attempts.
	lastPhaseTS time.Time
	// reaped is set true once the watchdog has escalated this worker. It is
	// checked under m.mu to make reaping idempotent.
	reaped bool
	// stopped is set true once an operator-driven Stop has started the
	// graceful termination path. Checked under m.mu so a second Stop is a
	// no-op and runWorker can preserve the "stopped" state across its final
	// record write.
	stopped bool
	// wakeCh, when non-nil, signals an execute-loop worker's idle-poll
	// sleep to return early so the loop re-scans the ready queue. The
	// channel is buffered (cap 1) so a non-blocking send coalesces multiple
	// wake calls into at most one extra tick. Set on execute-loop workers;
	// nil on plugin-action workers.
	wakeCh chan struct{}
}

// WorkerManager manages in-process execute-loop workers as goroutines.
type WorkerManager struct {
	projectRoot string
	rootDir     string
	// BeadWorkerFactory, when non-nil, is called by runWorker to create the
	// ExecuteBeadWorker instead of building one from the real agent runner.
	// Override in tests to inject a fake executor.
	BeadWorkerFactory func(store agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker

	// LandCoordinators is the per-project registry of land coordinators.
	// Exported so tests and server integration tests can stop coordinators
	// on teardown, or inject a custom LandingGitOps via

				Model:       spec.ReviewModel,
			}
		}

		worker = &agent.ExecuteBeadWorker{
			Store:    store,
			Executor: executor,
			Reviewer: reviewer,
		}
	}

	landingOps := agent.RealLandingGitOps{}

	loopResult, err := worker.Run(ctx, rcfg, agent.ExecuteBeadLoopRuntime{
		Once:                  spec.Once,
		PollInterval:          spec.PollInterval,
		Log:                   log,
		EventSink:             eventSink,
		WorkerID:              id,
		ProjectRoot:           projectRoot,
		LabelFilter:           spec.LabelFilter,
		ProgressCh:            progressCh,
		PreClaimHook:          buildPreClaimHook(projectRoot, landingOps),
		PreClaimIntakeHook:    intakeHook,
		PreDispatchLintHook:   lintHook,
		PostAttemptTriageHook: triageHook,
		NoReview:              spec.NoReview,
		ReviewCostCap:         costCap,
		WakeCh:                handle.wakeCh,
	})
	// Signal end of progress events so drainProgress can finish
	close(progressCh)
	// Wait for drainProgress to process all remaining events (including live
	// counter increments) before we overwrite handle.record with the final state.
	<-handle.progressDone

	m.mu.Lock()
	record := handle.record
	// Preserve terminal state set by Stop() or the watchdog so the final
	// writeRecord below does not overwrite "stopped" / "reaped" with
	// "exited" / "failed".
	preservedState := ""
	if record.State == "stopped" || record.State == "reaped" {
		preservedState = record.State
	}
	record.FinishedAt = time.Now().UTC()
	// Terminal worker: clear any "idle" substate (ddx-dc157075 AC #5; substate
	// is only meaningful while the worker is running).
	record.Substate = ""
	_ = handle.logFile.Close()

	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
	} else {
		record.State = "exited"
		record.Attempts = loopResult.Attempts
		record.Successes = loopResult.Successes
		record.Failures = loopResult.Failures

		if loopResult.NoReadyWork {
			record.Status = "no_ready_work"
		} else if loopResult.Failures > 0 && loopResult.Successes == 0 {
			record.Status = "execution_failed"
			if loopResult.LastFailureStatus != "" {
				record.Status = loopResult.LastFailureStatus
			}
		} else if loopResult.Successes > 0 {
			record.Status = "success"
		} else {
			record.Status = "exited"
		}

		if len(loopResult.Results) > 0 {
			last := loopResult.Results[len(loopResult.Results)-1]
			r := WorkerExecutionResult{
				BeadID:     last.BeadID,
				AttemptID:  last.AttemptID,
				WorkerID:   last.WorkerID,
				Harness:    last.Harness,
				Tier:       last.Tier,
				Provider:   last.Provider,
				Model:      last.Model,
				Status:     last.Status,
				Detail:     last.Detail,
				SessionID:  last.SessionID,
				BaseRev:    last.BaseRev,
				ResultRev:  last.ResultRev,
				RetryAfter: last.RetryAfter,
			}
			record.CurrentBead = last.BeadID
			record.LastResult = &r
			if last.Detail != "" {
				record.LastError = last.Detail
			}
			if last.Harness != "" && record.Harness == "" {
				record.Harness = last.Harness
			}
			if last.Model != "" && record.Model == "" {
				record.Model = last.Model
			}
			if last.Provider != "" && record.Provider == "" {
				record.Provider = last.Provider
			}
		}
	}
	// Terminal-state override: if Stop() or the watchdog already marked
	// this worker, keep that label so external consumers see the reason.
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
	}
	_ = m.writeRecord(dir, record)
	handle.record = record
	m.mu.Unlock()
}

