// WorkerEdge is one edge in a WorkerConnection
type WorkerEdge struct {
	// The worker at this position
	Node *Worker `json:"node"`
	// Opaque cursor for pagination
	Cursor string `json:"cursor"`
}

// WorkerEvent is a progress or lifecycle event from a worker
type WorkerEvent struct {
	// Unique event identifier
	EventID string `json:"eventID"`
	// Worker that emitted this event
	WorkerID string `json:"workerID"`
	// Current execution phase (e.g. "pending", "running", "done")
	Phase string `json:"phase"`
	// Timestamp of the event
	Timestamp string `json:"timestamp"`
	// Log line output from the worker (if any)
	LogLine *string `json:"logLine,omitempty"`
	// Bead ID being executed (null if not executing a bead)
	BeadID *string `json:"beadID,omitempty"`
}

// WorkerExecutionResult captures the outcome of one execution
type WorkerExecutionResult struct {
	// Bead that was executed
	BeadID *string `json:"beadId,omitempty"`
	// Unique attempt identifier
	AttemptID *string `json:"attemptId,omitempty"`
	// Worker that ran the execution
	WorkerID *string `json:"workerId,omitempty"`
	// Harness used
	Harness *string `json:"harness,omitempty"`
	// Tier used
	Tier *string `json:"tier,omitempty"`
	// Provider used
	Provider *string `json:"provider,omitempty"`
	// Model used
	Model *string `json:"model,omitempty"`
	// Outcome status (e.g. "success", "failure", "timeout")
	Status *string `json:"status,omitempty"`
	// Human-readable outcome detail
	Detail *string `json:"detail,omitempty"`
	// Correlated agent session ID
	SessionID *string `json:"sessionId,omitempty"`
	// Git revision the execution started from
	BaseRev *string `json:"baseRev,omitempty"`
	// Git revision produced by the execution
	ResultRev *string `json:"resultRev,omitempty"`
	// Suggested retry delay (e.g. "30s")
	RetryAfter *string `json:"retryAfter,omitempty"`
}

// WorkerLifecycleEvent records an operator lifecycle action.
type WorkerLifecycleEvent struct {
	// Action name, such as start or stop
	Action string `json:"action"`
	// Actor identifier known to the server
	Actor string `json:"actor"`
	// When the action was recorded
	Timestamp string `json:"timestamp"`
	// Optional action detail
	Detail *string `json:"detail,omitempty"`
	// Bead involved in the action, if any
	BeadID *string `json:"beadId,omitempty"`
}

// WorkerLifecycleResult describes a lifecycle mutation result.
type WorkerLifecycleResult struct {
	// Worker identifier
	ID string `json:"id"`
	// Worker state after the mutation was accepted
	State string `json:"state"`
	// Worker kind
	Kind string `json:"kind"`
}

// WorkerLog holds captured output from a worker process
type WorkerLog struct {
	// Captured standard output
	Stdout string `json:"stdout"`
	// Captured standard error
	Stderr string `json:"stderr"`
}

// WorkerRecentEvent is one captured response frame in worker detail history
type WorkerRecentEvent struct {
	// Event kind: text_delta or tool_call
	Kind string `json:"kind"`
	// Text content for text_delta events
	Text *string `json:"text,omitempty"`
	// Tool name for tool_call events
	Name *string `json:"name,omitempty"`
	// Tool call input payload encoded as JSON text
	Inputs *string `json:"inputs,omitempty"`
	// Tool call output text
	Output *string `json:"output,omitempty"`
}

